INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 21, 'teens', 1, 'Which city had not sent any men to the assembly at Mizpeh, and what did Israel do to it?', 'Jabesh-gilead; Israel slew all its inhabitants except four hundred young virgins', 'Shiloh; Israel burned it and took all its silver', 'Beth-el; Israel fasted there and spared all its people', 'Jericho; Israel rebuilt its walls as punishment', 'a', 'Judges 21:10-11 — "And the congregation sent thither twelve thousand men of the valiantest, and commanded them, saying, Go and smite the inhabitants of Jabesh-gilead with the edge of the sword...and the virgins ye shall save alive." Four hundred virgins were found.'),
('Judges', 21, 'teens', 2, 'The four hundred virgins from Jabesh-gilead were not enough for all six hundred Benjamite survivors. How did Israel solve the problem of the remaining two hundred?', 'They told Benjamin to hide and catch wives from the daughters of Shiloh who danced at the annual feast', 'They held a lottery to determine which two hundred Benjamites must remain unmarried', 'They went to battle against another city to find more women', 'They permitted Benjamin to take Canaanite women despite the oath', 'a', 'Judges 21:20-21 — "Therefore they commanded the children of Benjamin, saying, Go and lie in wait in the vineyards; And see, and, behold, if the daughters of Shiloh come out to dance in dances...catch you every man his wife of the daughters of Shiloh."'),
('Judges', 21, 'teens', 3, 'How did Israel justify the plan at Shiloh without technically breaking their oath not to give their daughters to Benjamin?', 'They argued that they would not be "giving" their daughters — the Benjamites would take the women, so the fathers would not have violated their oath', 'They said the oath was invalid because it had been sworn in anger', 'They consulted the high priest who annulled the oath by priestly authority', 'They gave silver to the fathers as compensation, making it a sale rather than a gift', 'a', 'Judges 21:22 — "when their fathers or their brethren come unto us to complain, that we shall say unto them, Be favourable unto them for our sakes: because we reserved not to each man his wife in the war: for ye did not give unto them at this time, that ye should be guilty." The argument turns on the legal technicality of "giving" versus "taking."'),
('Judges', 21, 'teens', 4, 'Where did the surviving men of Benjamin go to wait for the daughters of Shiloh to dance?', 'They hid in the vineyards of Shiloh', 'They waited at the city gate of Shiloh', 'They camped at the rock of Rimmon near Shiloh', 'They gathered at the tabernacle entrance', 'a', 'Judges 21:20-21 — "Therefore they commanded the children of Benjamin, saying, Go and lie in wait in the vineyards; And see, and, behold, if the daughters of Shiloh come out to dance in dances, then come ye out of the vineyards."'),
('Judges', 21, 'teens', 5, 'After receiving their wives, where did the Benjamites go and what did they do there?', 'They returned to their inheritance, repaired the cities, and dwelt in them', 'They lived at Shiloh permanently as a sign of gratitude', 'They went to Mizpeh to renew the covenant with Israel', 'They went to Gibeah and rebuilt the city exactly as it was before the war', 'a', 'Judges 21:23 — "And the children of Benjamin did so, and took them wives, according to their number, of them that danced, whom they caught: and they went and returned unto their inheritance, and repaired the cities, and dwelt in them."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('Judges', 21, 'adults', 1, 'What is the moral irony of Israel''s grief in Judges 21:2-3 — weeping before God that one tribe is missing — in light of what they themselves did to bring about that situation?', 'Israel was the direct agent of Benjamin''s near-destruction, yet mourns its consequences before God as though the disaster were an external affliction — the grief is genuine but self-created, a pattern of sowing covenant chaos and then lamenting the harvest', 'Israel''s grief was entirely appropriate and God approved their mourning without qualification', 'The decimation of Benjamin was solely God''s direct act and Israel bore no responsibility', 'Israel''s grief was hypocritical but God did not acknowledge it', 'a', 'Judges 21:3 — "O LORD God of Israel, why is this come to pass in Israel, that there should be to day one tribe lacking in Israel?" Their question "why?" reveals a lack of self-awareness about their own role as agents of the near-extermination described in chapter 20.'),
('Judges', 21, 'adults', 2, 'What does the destruction of Jabesh-gilead — an Israelite city — to obtain wives for Benjamin reveal about the escalating logic of vow-keeping in Israel?', 'To keep one oath (not giving daughters to Benjamin) they slaughtered an entire Israelite city and enslaved its virgin daughters — demonstrating that rigid oath-keeping without wisdom and mercy generates new atrocities worse than the original violation', 'The destruction of Jabesh-gilead was a separate act of justified holy war with no connection to the Benjamin problem', 'Killing the inhabitants of Jabesh-gilead was merciful compared to the alternative', 'The oath required Israel to find wives for Benjamin regardless of the cost, justifying any means', 'a', 'Judges 21:10-11 — Israel commanded twelve thousand men to "smite the inhabitants of Jabesh-gilead with the edge of the sword." The solution to one moral crisis generates a fresh massacre, illustrating how human schemes to fix covenant failures compound the disaster.'),
('Judges', 21, 'adults', 3, 'What is the canonical significance of the connection between Jabesh-gilead and Benjamin established in Judges 21, in light of 1 Samuel 11 and 31?', 'The four hundred virgins given to Benjamin created a bond of loyalty between Jabesh-gilead and Benjamin that explains why Jabesh-gilead rescued Saul''s body (1 Sam. 31:11-13) and why Saul, a Benjamite, championed Jabesh-gilead (1 Sam. 11) — Judges 21 provides the backstory for these later events', 'There is no canonical connection between Judges 21 and 1 Samuel', 'The connection is purely geographic and has no genealogical or loyalty dimension', 'Jabesh-gilead''s loyalty to Saul was based on geography, not on the marriage bond of Judges 21', 'a', '1 Samuel 31:11-12 — "when the inhabitants of Jabesh-gilead heard of that which the Philistines had done to Saul...all the valiant men arose, and went all night, and took the body of Saul." The loyalty to Saul''s Benjamite house preserved by the Judges 21 marriage bond makes this one of the Bible''s most carefully constructed long-range narrative connections.'),
('Judges', 21, 'adults', 4, 'How does the Shiloh vine-dance ambush compare to the earlier abduction of women in Israel''s tradition (Numbers 31) and what does the comparison reveal?', 'Israel moved from using war captives (Num. 31) to authorising the abduction of its own people''s daughters at a religious festival — showing a progressive degradation where sacred space (a religious feast) became the site of legalistic kidnapping within the covenant community itself', 'The Shiloh plan was more ethical than Numbers 31 because no one was killed', 'The comparison shows Israel was improving morally by finding a non-violent solution', 'There is no meaningful ethical comparison between the two passages', 'a', 'Judges 21:21 — "catch you every man his wife of the daughters of Shiloh." The annual feast at Shiloh was a sacred gathering before God. Its exploitation for wife-seizure represents the complete collapse of the distinction between holy and profane that the Mosaic law was designed to maintain.'),
('Judges', 21, 'adults', 5, 'What does the fourfold repetition of "no king in Israel" as a refrain in Judges 17-21 argue about the structure of the book''s theology?', 'The epilogue builds a cumulative case that covenant chaos — idolatry (chs. 17-18), sexual violence and civil war (chs. 19-21) — flows from the absence of God''s kingship mediated through a righteous human king, setting up the theological argument for the monarchy in 1 Samuel', 'The refrain argues Israel never needed a king and managed well without one', 'It argues only that human political leadership was absent, with no theological dimension about divine kingship', 'The refrain is a later addition by a pro-monarchical editor trying to justify Saul''s coronation', 'a', 'Judges 17:6; 18:1; 19:1; 21:25 — the refrain appears four times in the epilogue. In its final form (21:25 — "every man did that which was right in his own eyes") it diagnoses the root problem: Israel had become autonomous rather than theonomous, each person their own sovereign.'),
('Judges', 21, 'adults', 6, 'What is the theological significance of the book of Judges ending with "every man did that which was right in his own eyes" rather than with a restoration or a prayer of repentance?', 'The deliberately unresolved ending places the reader in suspense — this is not the end of the story but a diagnosis requiring a solution the book of Ruth and 1 Samuel will begin to provide through the Davidic covenant', 'The ending implies God had permanently abandoned Israel at the close of the judges period', 'The ending is a neutral historical observation without theological intention', 'The ending suggests the judges period was overall positive because each person had freedom', 'a', 'Judges 21:25 — "In those days there was no king in Israel: every man did that which was right in his own eyes." The book of Ruth, which follows canonically, immediately presents a counter-example of covenant faithfulness — and both Ruth and 1 Samuel build toward David, the king whose coming is the implicit answer to Judges'' repeated refrain.'),
('Judges', 21, 'adults', 7, 'How does the tribe of Benjamin''s near-extermination and miraculous preservation in Judges 20-21 function in light of the tribe''s later canonical importance?', 'The six hundred survivors at the rock of Rimmon are the ancestral remnant from whom Saul (1 Sam. 9:1), Paul/Saul of Tarsus (Phil. 3:5), and Queen Esther (Esth. 2:5) descended — making the tribe''s survival a matter of canonical providence', 'Benjamin''s survival had no notable canonical significance beyond providing a complete twelve-tribe nation', 'The tribe of Benjamin was largely absorbed into Judah and lost its distinct identity after Judges 21', 'The survivors at Rimmon were not the ancestors of Saul; he came from a different Benjamite line', 'a', 'Judges 20:47 — "six hundred men turned and fled to the wilderness unto the rock Rimmon." Romans 11:1 — "I also am an Israelite, of the seed of Abraham, of the tribe of Benjamin." Paul''s claim of Benjamite identity traces back through Saul to the very survivors of Judges 20-21.'),
('Judges', 21, 'adults', 8, 'How does Judges 21 as a whole model the pattern described in Romans 3:8 — "let us do evil that good may come" — and why does the biblical narrative present this without explicit condemnation of the Israelite leaders?', 'Israel''s leaders reasoned that massacring Jabesh-gilead and orchestrating the Shiloh kidnapping were necessary goods to preserve the twelve-tribe structure — the narrative presents their schemes without endorsing them, leaving the reader to evaluate whether pragmatic evil can produce genuine good', 'The narrative explicitly approves all of Israel''s decisions in chapter 21', 'The absence of divine judgment in the text means God approved of the solutions Israel devised', 'The chapter condemns only the Benjamites while praising Israel''s pragmatic wisdom', 'a', 'Judges 21:22-23 — Israel''s leaders defend the Shiloh plan as clever loophole-keeping. No divine voice endorses or condemns. The text''s silence is itself an interpretive feature — the reader who has followed the entire book of Judges from chapter 2''s framework understands that clever human solutions that bypass God''s law are precisely what the book diagnoses as the root disease of this era.');
